import type { InterpolationOptions } from 'i18next';

/** Shared i18next interpolation config. Disables HTML escaping (React handles that) and adds `{{ value, number }}` formatting via `toLocaleString`. */
export const defaultInterpolation: InterpolationOptions = {
    escapeValue: false,
    format: (value, format) => {
        if (format === 'number' && typeof value === 'number') {
            return value.toLocaleString();
        }
        return value;
    },
};
